mapper.select:
select c.id, c.type, c.target_id, c.last_message_id, c.last_message_preview, c.last_message_at, c.created_at, c.updated_at, c.deleted_at, cm.unread_count, cm.is_muted, cm.is_pinned, case when c.type = 'private' then pu.nickname when c.type = 'group' then g.name else '系统通知' end as title, case when c.type = 'private' then pu.avatar_url else null end as avatar_url from cook_conversations c inner join cook_conversation_members cm on cm.conversation_id = c.id and cm.user_id = #{userId} and cm.status = 'normal' left join cook_conversation_members other_cm on other_cm.conversation_id = c.id and other_cm.user_id <> #{userId} and other_cm.status = 'normal' and c.type = 'private' left join cook_users pu on pu.id = other_cm.user_id and pu.deleted_at is null left join `cook_groups` g on g.id = c.target_id and g.deleted_at is null where c.deleted_at is null
and c.type = #{type}
order by cm.is_pinned desc, c.last_message_at desc, c.updated_at desc, c.id desc
